#include<bits/stdc++.h>
using namespace std;
int t,a,p;
int mypow(int x){
    int s=a,ans=1;
    while(x){
        if(x&1)ans=1ll*ans*s%p;
        x>>=1,s=1ll*s*s%p;
    }
    return ans;
}
bool check(){
    int x=p-1;
    if(mypow(x)!=1)return false;
    for(int i=2;i<=sqrt(x);i++) {
        if (x % i == 0) {
            if (mypow(i) == 1||mypow(x/i)==1)return false;
        }
    }
    return true;
}
int main(){
    cin>>t;
    while(t--){
        cin>>a>>p;
        if(check()) cout<<"Yes\n";
        else cout<<"No\n";
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int n,g[130][130],d[2005];
string ans="";
void dfs(char u){
    for(int i='A';i<='z';i++){
        if(isalpha(char(i))) {
            if (g[u][i]) {
                g[u][i]=0;
                g[i][u]=0;
                dfs(i);
            }
        }
    }
    ans+=u;
}
int main() {
    cin>>n;
    int s=0;
    int x=n;
    char st='z';
    while(x--){
        char a,b;
        cin>>a>>b;
        st=min(st,a);
        st=min(st,b);
        g[a][b]=1;
        g[b][a]=1;
        d[a]++,d[b]++;
    }
    for(int i='A';i<='z';i++)
        if(isalpha(char(i)))
            if (d[i] % 2 == 1) s++;
    if(s==0 || s==2) {
        if(s==0)
            dfs(st);
        else{
            for(int i='A';i<='z';i++) {
                if(isalpha(char(i))) {
                    if (d[i] % 2 == 1) {
                        st = i;
                        break;
                    }
                }
            }
            dfs(st);
        }
    }
    else {
        cout << "No Solution";
        return 0;
    }
    for(int i=ans.size()-1;i>=0;i--){
        cout<<ans[i];
    }
    return 0;
}

#include<bits/stdc++.h>
using namespace std;
const int N = 2e5 + 5;
typedef long long LL;
typedef pair<LL,int>PII;
vector<PII>g[N];
int n,m,st;
LL dist[N],vis[N];

int dij(){
    memset(dist,0x3f,sizeof(dist));
    dist[st]=0;
    priority_queue<PII,vector<PII>,greater<PII>>h;
    h.push({0,st});
    while(h.size()){
        PII t=h.top();
        h.pop();
        int v=t.second;
        if(vis[v]) continue;
        vis[v]=true;
        for(auto xx:g[v]){
            LL i=xx.first,w=xx.second;
            if(dist[v]+w<dist[i]){
                dist[i]=dist[v]+w;
                h.push({dist[i],i});
            }
        }
    }
    if(dist[n]==0x3f3f3f3f3f3f3f3f) return -1;
    return dist[n];

}
int main(){
    scanf("%d%d%d",&n,&m,&st);
    for(int i=1;i<=m;i++){
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        g[a].push_back({b,c});
    }
    dij();
    for(int i=1;i<=n;i++){
        printf("%lld ",dist[i]);
    }
    return 0;
}

