#include<bits/stdc++.h>
using namespace std;
const int N=1e6+5;
int t[N],idx;
int n,op,x;
void up(int u){
    while(u/2>=1 && t[u]<t[u/2]){
        swap(t[u],t[u/2]);
        u/=2;
    }
}
void down(int u){
    int p=u;
    if(u*2<=idx && t[u*2]<t[p]) p=u*2;
    if(u*2+1<=idx && t[u*2+1]<t[p]) p=u*2+1;
    if(p!=u){
        swap(t[u],t[p]);
        down(p);
    }
}
void push(int x){
    t[++idx]=x;
    up(idx);
}
void pop(){
    t[1]=t[idx--];
    down(1);
}
int main(){
    scanf("%d",&n);
    while(n--){
        scanf("%d",&op);
        if(op==1){
            scanf("%d",&x);
            push(x);
        }else if(op==2){
            printf("%d\n",t[1]);
        }else pop();
    }
    return 0;
}

#include<bits/stdc++.h>
using namespace std;
const int N = 1e5 + 5;
typedef long long LL;
typedef pair<LL,int>PII;
vector<PII>g[N];
int n,m,st;
LL dist[N],vis[N];

int spfa(){
    memset(dist,0x3f,sizeof(dist));
    dist[st]=0;
    queue<int>q;
    q.push(st);vis[st]=1;
    while(q.size()){
        int v=q.front();
        q.pop();
        vis[v]=0;
        for(auto xx:g[v]) {
            LL i = xx.first, w = xx.second;
            if (dist[v] + w < dist[i]) {
                dist[i] = dist[v] + w;
                if (!vis[i]) {
                    q.push(i);vis[i] = 1;
                }
            }
        }
    }
    for(int i=1;i<=n;i++) {
        if (dist[i] == 0x3f3f3f3f3f3f3f3f) return -1;
    }
    return dist[n];

}
int main(){
    scanf("%d%d%d",&n,&m,&st);
    for(int i=1;i<=m;i++){
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        g[a].push_back({b,c});
    }
    spfa();
    for(int i=1;i<=n;i++){
        if(dist[i]==0x3f3f3f3f3f3f3f3f)printf("%lld ",INT_MAX);
        else printf("%lld ",dist[i]);
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> a(n+ 1);
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    for (int len = 1; len <= n; ++len) {
        for (int l = 1; l + len - 1 <= n; l++) {
            int r = l + len - 1,t = n - (r - l);
            if (l == r) dp[l][r] = a[l] * t;
            else dp[l][r] = max(a[l] * t + dp[l + 1][r],a[r] * t + dp[l][r - 1]);
        }
    }
    cout << dp[1][n] << endl;
    return 0;
}

