#include <bits/stdc++.h>
using namespace std;
const int MAX = 1000010;
bool a[MAX];
int prime[MAX], cnt;
int b[MAX];
void get_prime(int n) {
    memset(a, 0, sizeof(a));
    a[0] = a[1] = 1;
    cnt = 0;
    for (int i = 2; i <= n; i++) {
        if (!a[i]) prime[++cnt] = i;
        for (int j = 1; j <= cnt && i <= n / prime[j]; j++) {
            a[i * prime[j]] = 1;
            if (i % prime[j] == 0) break;
        }
    }
}
int main() {
    ios::sync_with_stdio(0);
    cin.tie(0); cout.tie(0);
    int n, m;
    cin >> n >> m;
    get_prime(m);
    for (int i = 1; i <= m; i++) b[i] = b[i-1] + !a[i];
    while (n--) {
        int l, r;cin >> l >> r;
        if (l < 1 || r > m || l > m || r < 1) cout << "Crossing the line" << endl;
        else cout << b[r] - b[l-1] << endl;
    }
    return 0;
}

