#define ll long long
const int mod=10000;
int f[10001];
ll ksm(ll a,ll b,ll c){
    ll ans=1;
    while (b){
        if (b%2==1) ans=(ans*a)%c;
        a=(a*a)%c;
        b/=2;
    }
    return ans;
}
int main()
{
    int n,i,s,a,b;
    scanf("%d",&n);
    memset(f,0,sizeof(f));
    while(n--){
        s=0;
        scanf("%d%d",&a,&b);
        for (i=1;i<=mod;i++) f[i]=(f[i-1]+ksm(i,b,mod))%mod;
        s=(a/mod*f[mod]+f[a%mod])%mod;
        printf("%d\n",s);
    }
}

#include<bits/stdc++.h>
