const int N = 1e5+10;
int n,a[N],p[N][20],s;
void f(int x){
    if(x == 1) return;
    unordered_map<int, int> t;
    for(int i=2;i*i<=x;i++){
        while(x % i == 0){
            p[i][++t[i]]++;
            x /= i;
        }
        if(x == 1) return;
    }
    p[x][++t[x]]++;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        f(a[i]);
    }
    for(int i=2;i<=1e5;i++){
        for(int j=1;j<20;j++){
            if(!p[i][j]) break;
            s += min(p[i][j], n - p[i][j]);
        }
    }
    cout<<s;
    return 0;
}

