#include<bits/stdc++.h>

using namespace std;
int n, m, a, b, x, x2, y, y2, vis[1000][1000];
struct node {
    int x, y, step;
};
queue<node> q;
int dir[4][2] = {{-1, 0},
                 {1,  0},
                 {0,  -1},
                 {0,  1}};

bool check(int x,int y) {
    return x >= 1 && x <= n && y >= 1 && y <= m && vis[x][y] == -1;
}
void bfs() {
    while (!q.empty()) {
        node t = q.front();
        q.pop();
        for (int i = 0; i < 4; i++) {
            int dx = t.x + dir[i][0];
            int dy = t.y + dir[i][1];
            if (check(dx, dy)) {
                q.push({dx, dy});
                vis[dx][dy] = vis[t.x][t.y] + 1;
            }
        }
    }
}

int main() {
    cin >> n >> m >> a >> b;
    memset(vis, -1, sizeof vis);
    for (int i = 1; i <= a; i++) {
        cin >> x >> y;
        q.push({x, y});
        vis[x][y] = 0;
    }
    bfs();
    for (int i = 1; i <= b; i++) {
        cin >> x2 >> y2;
        cout << vis[x2][y2]<<endl;
    }
    return 0;
}

#include <bits/stdc++.h>
#define ll long long
using namespace std;

ll n, m, a, b, l, r, ans;

bool ck(ll t) {
    if (t == 0) return true;
    if (a == b) return t <= n / a && t <= m / a;
    ll d, le, rr, xl, xr;
    if (a > b) {
        d = a - b;
        rr = n - b * t;
        le = a * t - m;
        if (rr < 0 || le > d * t)
            return false;
        if (le <= 0) xl = 0; else xl = (le + d - 1) / d;
        xr = rr / d;
    } else {
        d = b - a;
        le = b * t - n;
        rr = m - a * t;
        if (rr < 0 || le > d * t) return false;
        if (le <= 0) xl = 0; else xl = (le + d - 1) / d;
        xr = rr / d;
    }
    if (xl > xr || xl > t || xr < 0)
        return false;
    return true;
}

int main() {
    cin >> n >> m >> a >> b;
    l = 0, r = (n + m) / min(a, b) + 1, ans = 0;
    while (l <= r) {
        ll mid = (l + r) >> 1;
        if (ck(mid)) ans = mid, l = mid + 1;
        else r = mid - 1;
    }
    cout << ans;
    return 0;
}

