#include <bits/stdc++.h>
using namespace std;
bool ck(int n) {
    if (n == 1)
        return true;
    for (int i = 2; i * i <= n; ++i)
        if (n % i == 0) {
            if (i != 2 && i != 5)
                return false;
            while (n % i == 0)
                n /= i;
        }
    if (n > 1)
        if (n != 2 && n!= 5) return false;
    return true;
}

int main() {
    int l, r;
    cin>>l>>r;
    int s = 0;
    for (int i = l; i <= r; ++i)
        if (ck(i))
            s++;
    cout << s << endl;
    return 0;
}

