#include <bits/stdc++.h>
using namespace std;
const int N = 10005;
struct xs {int i,c, m, e,s, t, x, r;};
xs a[N];
int s[N];
bool cmp(const xs u, const xs v) {
    if (u.s != v.s) return u.s > v.s;
    if (u.t != v.t) return u.t > v.t;
    if (u.x != v.x) return u.x > v.x;
    return false;
}
int main() {
    int n;
    cin >> n;
    for (int j = 0; j < n; j++) {
        cin >> a[j].c >> a[j].m >> a[j].e;
        a[j].i = j;
        a[j].s = a[j].c + a[j].m + a[j].e;
        a[j].t = a[j].c + a[j].m;
        if( a[j].c > a[j].m) a[j].x = a[j].c;
        else a[j].x = a[j].m;
    }
    sort(a, a + n, cmp);
    a[0].r = 1;
    for (int j = 1; j < n; ++j) {
        if (a[j].s == a[j-1].s && a[j].t == a[j-1].t && a[j].x == a[j-1].x) a[j].r = a[j-1].r;
        else a[j].r = j + 1;
    }
    for (int j = 0; j < n; j++)
        s[a[j].i] = a[j].r;
    for (int j = 0; j < n; j++)
        cout << s[j] << '\n';
    return 0;
}

