void solve(long long n) {
    bool f = true; 
    for (long long i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            int s = 0;
            while (n % i == 0) {
                n /= i;
                s++;
            }
            if (!f) cout << " * ";
            if (s > 1) cout << i << "^" << s;
            else cout << i;
            f = false;
        }
    }
    if (n > 1) {
        if (!f) cout << " * ";
        cout << n;
    }
}

