#include <bits/stdc++.h>
using namespace std;
const int N = 10000;
bool a[N];
int prime[500];
void get_prime(int n) {
    memset(a, 0, sizeof(a));
    a[0] = a[1] = 1;
    int cnt = 0;
    for (int i = 2; i < N; i++) {
        if (!a[i]) {
            prime[cnt++] = i;
            if (cnt >= n) return;
        }
        for (int j = 0; j < cnt && i * prime[j] < N; j++) {
            a[i * prime[j]] = 1;
            if (i % prime[j] == 0) break;
        }
    }
}
int main() {
    ios::sync_with_stdio(0);
    cin.tie(0); cout.tie(0);
    int n, x, y;
    cin >> n >> x >> y;
    int tot = n * n;
    get_prime(tot);
    int she[21][21] = {0};
    int dx[4] = {0, 1, 0, -1}, dy[4] = {1, 0, -1, 0};
    int d = 0, r = 0, c = 0;
    for (int i = 0; i < tot; i++) {
        she[r][c] = prime[i];
        int nr = r + dx[d], nc = c + dy[d];
        if (nr < 0 || nr >= n || nc < 0 || nc >= n || she[nr][nc]) {
            d = (d + 1) % 4;
            nr = r + dx[d];
            nc = c + dy[d];
        }
        r = nr; c = nc;
    }
    cout << she[x-1][y-1] << endl;
    return 0;
}

