using namespace std;
#define ll long long
int n,m,p[1005],s[1005];
ll c[1005],a[1005],b[1005];
int main(){
    cin >> n >> m;
    for (int i = 1; i <= m; i++)
        cin >> p[i] >> c[i];
    ll mn = 4e18;
    for (int k = 1; k <= m; k++){
        memset(s,0,sizeof s);
        for (int i = 1; i <= m; i++) s[p[i]]++;
        ll t = 0;
        int h = s[1], tot = 0;
        for (int i = 2; i <= n; i++){
            int cnt = 0;
            for (int j = 1; j <= m; j++)
                if (p[j]==i)
                    a[++cnt] = c[j];
            sort(a+1,a+cnt+1);
            int d = max(0,cnt-(k-1));
            for (int j = 1; j <= d; j++){
                t += a[j];
                h++;
            }
            for (int j = d+1; j <= cnt; j++)
                b[++tot] = a[j];
        }
        sort(b+1,b+tot+1);
        int i = 1;
        while (h < k){
            t += b[i++];
            h++;
        }
        mn = min(mn,t);
    }
    cout << mn << endl;
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int image[20][20];
int cpimg[20][20];
int his[256];
int color[16];
int trans(char a) {
   if (a <= '9')
       return (a- '0');
   return (a- 'A' + 10);
}
char itrans(int n) {
   if (n >= 10)
       return (char)(n- 10 + 'A');
   return (char)(n + '0');
}
int compress(int c) {
   int dis = 256, res =-1;
   for (int i = 0; i < 16; i++) {
       int d = c- color[i];
       if (d < 0)
           d =-d;
       if (d < dis) {
           dis = d;
           res = i;
       }
   }
   return res;
}
int main() {
   int N = 0, M = 0;
   cin >> N;
   for (int i = 0; i < 256; i++)
       his[i] = -1;
   for (int i = 0; i < N; i++) {
       char line[50];
       cin >> line;
       M = strlen(line) / 2;
       for (int j = 0; j < M; j++) {
           int c = trans(line[j * 2]) * 16 + trans(line[j * 2 + 1]);
           image[i][j] = c;
           his[c]++;
       }
   }
   for (int c = 0; c < 16; c++) {
       int max = 0, max_id = -1;
       for (int i = 0; i < 256; i++)
           if (his[i] > max) {
               max = his[i];
               max_id = i;
           }
       color[c] = max_id;
       his[max_id] = -1;
   }
   for (int i = 0; i < N; i++)
       for (int j = 0; j < M; j++)
           cpimg[i][j] = compress(image[i][j]);
   for (int c = 0; c < 16; c++)
       cout << itrans(color[c] / 16) << itrans(color[c] % 16);
   cout << endl;
   for (int i = 0; i < N; i++) {
       for (int j = 0; j < M; j++)
           cout << itrans(cpimg[i][j]);
       cout << endl;
   }
   return 0;
}
